const requestBody = {
  model: "gpt-4o",
  input: [
    { role: "system", content: "Voce e um extrator de dados de documentos financeiros. Analise o documento e extraia as informacoes. Responda APENAS com JSON valido, sem markdown, sem explicacoes." },
    {
      role: "user",
      content: [
        { type: "input_file", file_id: fileId },
        { type: "input_text", text: prompt }
      ]
    }
  ]
};

return [{ json: { requestBody: JSON.stringify(requestBody) } }];

const raw = $input.first().json;
let content = '';

try {
  content = raw.choices[0].message.content;
} catch (e1) {
  try {
    const msgBlock = raw.output.find(o => o.type === 'message');
    const textBlock = msgBlock.content.find(c => c.type === 'output_text');
    content = textBlock.text;
  } catch (e2) {
    throw new Error('Resposta Vision invalida: ' + JSON.stringify(raw).substring(0, 500));
  }
}

content = content.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(content);
} catch (e) {
  throw new Error('JSON invalido: ' + content);
}

const categoria = (parsed.categoria || '').toLowerCase().trim();
const isEntrada = categoria.includes('entrada');
const valor = parseFloat(parsed.valor) || 0;
const tipoDoc = parsed.tipo_documento || 'comprovante_simples';
const itens = parsed.itens || [];

let itensFormatados = '';
if (itens.length > 0) {
  itensFormatados = itens
    .map(i => '  \u2022 ' + i.descricao + ' (' + i.quantidade + 'x) \u2014 R$ ' + parseFloat(i.valor_total).toFixed(2))
    .join('\n');
}

return [{
  json: {
    tipo_documento: tipoDoc,
    data_transacao: parsed.data_transacao || new Date().toLocaleDateString('pt-BR'),
    transacao: parsed.transacao || 'Comprovante financeiro',
    estabelecimento: parsed.estabelecimento || null,
    categoria: isEntrada ? 'entrada' : 'sa\u00edda',
    entrada: isEntrada ? valor : 0,
    saida: isEntrada ? 0 : valor,
    itens: itens,
    itens_formatados: itensFormatados,
    tem_itens: itens.length > 0
  }
}];

